import{_ as a,o as r,c as l,a2 as e}from"./chunks/framework.DIMps2S2.js";const c=JSON.parse('{"title":"行情与全景","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/overview.md","filePath":"zh-CN/market-data/overview.md"}'),i={name:"market-data/overview.md"};function d(o,t,h,n,s,u){return r(),l("div",null,[...t[0]||(t[0]=[e('<h1 id="行情与全景" tabindex="-1">行情与全景 <a class="header-anchor" href="#行情与全景" aria-label="Permalink to &quot;行情与全景&quot;">​</a></h1><p>个股和 ETF 详情页包含多个标签，行情和全景是最常用的两个核心标签，分别提供实时报价数据和基本面信息。</p><p>入口：长桥 App - 市场/自选 - 点击标的进入详情页</p><h2 id="行情-tab" tabindex="-1">行情 Tab <a class="header-anchor" href="#行情-tab" aria-label="Permalink to &quot;行情 Tab&quot;">​</a></h2><h3 id="基本行情数据" tabindex="-1">基本行情数据 <a class="header-anchor" href="#基本行情数据" aria-label="Permalink to &quot;基本行情数据&quot;">​</a></h3><p>页面顶部展示核心报价信息：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>最新价 / 涨跌幅</td><td>当前成交价及较昨收的涨跌幅</td></tr><tr><td>昨收</td><td>上一交易日收盘价</td></tr><tr><td>今开</td><td>当日开盘价</td></tr><tr><td>最高 / 最低</td><td>当日最高价和最低价</td></tr><tr><td>成交量</td><td>当日累计成交股数</td></tr><tr><td>成交额</td><td>当日累计成交金额</td></tr><tr><td>振幅</td><td>（最高价 - 最低价）/ 昨收价</td></tr><tr><td>换手率</td><td>成交量 / 流通股本</td></tr><tr><td>量比</td><td>当日成交量与近期均量的比值</td></tr><tr><td>委比</td><td>（买盘委托量 - 卖盘委托量）/ 总委托量，反映买卖力度对比</td></tr><tr><td>均价</td><td>当日成交均价（成交额 / 成交量）</td></tr><tr><td>总市值 / 流通市值</td><td>总股本 / 流通股本对应市值</td></tr><tr><td>总股本 / 流通股本</td><td>总份额和可流通份额</td></tr><tr><td>每手</td><td>最小交易单位</td></tr><tr><td>货币</td><td>计价货币（如 USD、HKD）</td></tr><tr><td>52 周高 / 52 周低</td><td>近 52 周最高价和最低价</td></tr><tr><td>每股净资产</td><td>账面价值或基金单位净值</td></tr><tr><td>每股收益</td><td>EPS</td></tr><tr><td>市盈率</td><td>PE（TTM / 动态 / 静态可切换）</td></tr><tr><td>市净率</td><td>PB</td></tr><tr><td>股息 / 股息率</td><td>近期每股分红金额及对应股息率</td></tr></tbody></table><h3 id="盘前-盘后交易" tabindex="-1">盘前 / 盘后交易 <a class="header-anchor" href="#盘前-盘后交易" aria-label="Permalink to &quot;盘前 / 盘后交易&quot;">​</a></h3><p>支持美股盘前和盘后延长时段行情，顶部显示当前交易时段状态（如「盘前交易中 美东时间」），盘前价格和涨跌幅单独展示。</p><h3 id="bbo-最优买卖报价" tabindex="-1">BBO（最优买卖报价） <a class="header-anchor" href="#bbo-最优买卖报价" aria-label="Permalink to &quot;BBO（最优买卖报价）&quot;">​</a></h3><p>显示当前买一价和卖一价（Best Bid &amp; Offer），以及对应的委托量，帮助判断即时买卖报价水平。</p><h3 id="深度摆盘" tabindex="-1">深度摆盘 <a class="header-anchor" href="#深度摆盘" aria-label="Permalink to &quot;深度摆盘&quot;">​</a></h3><ul><li>默认显示买卖双方各 5 档报价和委托量</li><li>订阅 <strong>Nasdaq TotalView</strong> 后可查看 60 档深度摆盘，获取更完整的市场深度数据</li><li>买盘（绿色）/ 卖盘（红色）分列展示，直观显示多空力量分布</li></ul><h3 id="k-线图表" tabindex="-1">K 线图表 <a class="header-anchor" href="#k-线图表" aria-label="Permalink to &quot;K 线图表&quot;">​</a></h3><p>支持多周期切换：</p><ul><li><strong>分时图</strong>：1 分钟实时走势，含成交量</li><li><strong>日 K / 周 K / 月 K / 年 K</strong>：不同周期蜡烛图</li><li><strong>5 日分时</strong>：近 5 个交易日连续分时走势</li></ul><p>内置常用技术指标：</p><ul><li><strong>MACD</strong>：趋势与动量指标</li><li><strong>KDJ</strong>：超买超卖判断</li><li><strong>RSI</strong>：相对强弱指数</li><li><strong>VOL</strong>：成交量柱状图</li></ul><h3 id="资金流向" tabindex="-1">资金流向 <a class="header-anchor" href="#资金流向" aria-label="Permalink to &quot;资金流向&quot;">​</a></h3><p>展示资金流入流出情况：</p><ul><li><strong>实时资金流向</strong>：当日按大单 / 中单 / 小单分类的资金流入和流出金额（单位：万元）</li><li><strong>历史资金流向</strong>：近期多日资金流向趋势，判断主力资金动向</li></ul><h3 id="做空数据" tabindex="-1">做空数据 <a class="header-anchor" href="#做空数据" aria-label="Permalink to &quot;做空数据&quot;">​</a></h3><p>展示做空相关统计数据，帮助了解市场空头仓位情况。</p><h3 id="成交统计" tabindex="-1">成交统计 <a class="header-anchor" href="#成交统计" aria-label="Permalink to &quot;成交统计&quot;">​</a></h3><p>按买卖方向和单笔成交规模统计当日成交分布情况。</p><h3 id="大家也在关注" tabindex="-1">大家也在关注 <a class="header-anchor" href="#大家也在关注" aria-label="Permalink to &quot;大家也在关注&quot;">​</a></h3><p>与当前标的相关的其他标的（同行业或关联板块），显示各标的当日涨跌幅，便于横向对比。</p><h3 id="相关资讯" tabindex="-1">相关资讯 <a class="header-anchor" href="#相关资讯" aria-label="Permalink to &quot;相关资讯&quot;">​</a></h3><p>行情页底部展示相关的市场资讯和新闻，来源包括多家财经媒体。数据来自第三方数据源，仅供参考，不构成投资建议。</p><hr><h2 id="全景-tab-—-个股" tabindex="-1">全景 Tab — 个股 <a class="header-anchor" href="#全景-tab-—-个股" aria-label="Permalink to &quot;全景 Tab — 个股&quot;">​</a></h2><p>个股全景提供上市公司的完整基本面资料。</p><h3 id="公司概况" tabindex="-1">公司概况 <a class="header-anchor" href="#公司概况" aria-label="Permalink to &quot;公司概况&quot;">​</a></h3><ul><li>公司简介：公司主营业务、成立时间、注册地、上市日期等基本信息</li><li>行业分类：所属行业板块</li><li>管理层信息：高管团队和董事会成员</li><li>联系方式：公司地址、官网、投资者关系联系方式</li></ul><p>财务数据详情（三大报表及核心财务指标）请参考 <a href="/wiki/market-data/financials">财务分析</a>。</p><h3 id="股东信息" tabindex="-1">股东信息 <a class="header-anchor" href="#股东信息" aria-label="Permalink to &quot;股东信息&quot;">​</a></h3><ul><li>股本结构：总股本、流通股本</li><li>主要股东：前十大股东持股比例</li><li>机构持仓：机构投资者持仓变动</li></ul><h3 id="分红信息" tabindex="-1">分红信息 <a class="header-anchor" href="#分红信息" aria-label="Permalink to &quot;分红信息&quot;">​</a></h3><ul><li>历史分红记录：派息日期、每股股息金额、股息率</li><li>分红方式：现金派息、送股、选股选息</li><li>除权除息日、登记日、派息日等关键日期</li></ul><p>查看路径：个股详情页 - 全景 - 百科 - 分红</p><h3 id="分析师评级" tabindex="-1">分析师评级 <a class="header-anchor" href="#分析师评级" aria-label="Permalink to &quot;分析师评级&quot;">​</a></h3><ul><li>目标价：分析师给出的目标价格区间</li><li>评级分布：买入、增持、中性、减持、卖出的数量分布</li><li>评级变动：近期分析师评级调整情况</li></ul><h3 id="公司公告与新闻" tabindex="-1">公司公告与新闻 <a class="header-anchor" href="#公司公告与新闻" aria-label="Permalink to &quot;公司公告与新闻&quot;">​</a></h3><ul><li>公司公告：财报发布、公司行动、重大事项公告</li><li>相关新闻：与该公司相关的市场新闻和资讯</li><li>社区讨论：投资者社区中关于该股票的讨论</li></ul><h3 id="portai-智能助手" tabindex="-1">PortAI 智能助手 <a class="header-anchor" href="#portai-智能助手" aria-label="Permalink to &quot;PortAI 智能助手&quot;">​</a></h3><p>长桥 App 内置 PortAI 智能信息助手，可通过对话方式获取个股相关信息，包括财务分析、行业对比、公司行动解读等，帮助高效理解投资信息。</p><hr><h2 id="全景-tab-—-etf" tabindex="-1">全景 Tab — ETF <a class="header-anchor" href="#全景-tab-—-etf" aria-label="Permalink to &quot;全景 Tab — ETF&quot;">​</a></h2><p>ETF 全景提供基金的基本面和分析数据。</p><p>入口：ETF 详情页 - 全景</p><h3 id="概况" tabindex="-1">概况 <a class="header-anchor" href="#概况" aria-label="Permalink to &quot;概况&quot;">​</a></h3><ul><li><strong>基金简介</strong>：ETF 的投资目标、跟踪指数、基金规模、成立时间等基本信息</li><li><strong>营收构成 / 业绩构成</strong>：主要持仓行业或地区分布（按占比展示）</li><li><strong>关注度排名</strong>：在同类标的中的用户关注度排名</li><li><strong>市值排名</strong>：在所属行业或板块中的市值排名</li></ul><h3 id="股价趋势" tabindex="-1">股价趋势 <a class="header-anchor" href="#股价趋势" aria-label="Permalink to &quot;股价趋势&quot;">​</a></h3><p>展示 ETF 在不同时间维度下的涨跌幅表现：</p><table tabindex="0"><thead><tr><th>时间段</th><th>说明</th></tr></thead><tbody><tr><td>当日</td><td>今日涨跌幅</td></tr><tr><td>1 周</td><td>近 7 日涨跌幅</td></tr><tr><td>1 月</td><td>近 30 日涨跌幅</td></tr><tr><td>6 月</td><td>近 6 个月涨跌幅</td></tr><tr><td>今年</td><td>年初至今涨跌幅</td></tr><tr><td>1 年 / 3 年</td><td>近 1 年 / 3 年涨跌幅</td></tr><tr><td>全部</td><td>上市以来总涨跌幅</td></tr></tbody></table><p>同时显示<strong>社区看涨比例</strong>和关注人数及表态条数。</p><h3 id="股票估值" tabindex="-1">股票估值 <a class="header-anchor" href="#股票估值" aria-label="Permalink to &quot;股票估值&quot;">​</a></h3><p>对 ETF 进行估值分析，提供三项核心指标：</p><ul><li><strong>市盈率（PE）</strong>：当前 PE 与历史区间、行业中位数的对比</li><li><strong>市净率（PB）</strong>：当前 PB 与历史区间、行业中位数的对比</li><li><strong>市销率（PS）</strong>：适合评估前期投入大、盈利周期慢的基金</li></ul><p>每项指标展示：当前值、合理区间、历史最大 / 最小值、平均值、中位值、行业中位数及同行业排名。</p><h3 id="财务评分" tabindex="-1">财务评分 <a class="header-anchor" href="#财务评分" aria-label="Permalink to &quot;财务评分&quot;">​</a></h3><p>根据最新财报综合评估基金财务状况，提供量化评分和描述，可与同行比较。</p><h3 id="成分股-持仓" tabindex="-1">成分股 / 持仓 <a class="header-anchor" href="#成分股-持仓" aria-label="Permalink to &quot;成分股 / 持仓&quot;">​</a></h3><ul><li><strong>成分股列表</strong>：ETF 跟踪指数的成分股名称、权重占比</li><li><strong>前十大持仓</strong>：持仓股票名称及持仓比例</li></ul><h3 id="分红" tabindex="-1">分红 <a class="header-anchor" href="#分红" aria-label="Permalink to &quot;分红&quot;">​</a></h3><p>历史分红记录，包含：</p><ul><li>除权除息日 / 登记日 / 派息日</li><li>每股（每份额）分红金额</li><li>分红频率（年度 / 季度 / 月度）</li></ul><h3 id="机构观点-分析师评级" tabindex="-1">机构观点 / 分析师评级 <a class="header-anchor" href="#机构观点-分析师评级" aria-label="Permalink to &quot;机构观点 / 分析师评级&quot;">​</a></h3><p>汇总机构分析师的评级意见：</p><ul><li>评级分布：强力推荐 / 买入 / 持有 / 跑输大盘 / 无意见</li><li>目标价区间</li></ul><h3 id="股东信息-1" tabindex="-1">股东信息 <a class="header-anchor" href="#股东信息-1" aria-label="Permalink to &quot;股东信息&quot;">​</a></h3><ul><li><strong>主要股东</strong>：持股比例最高的机构或个人股东列表，含持股数量、持股比例、持股变动及披露时间</li><li><strong>基金持仓</strong>：哪些 ETF 或基金持有该标的，显示基金名称、持仓占比和更新时间</li></ul><h3 id="利益相关者-投资关系" tabindex="-1">利益相关者 / 投资关系 <a class="header-anchor" href="#利益相关者-投资关系" aria-label="Permalink to &quot;利益相关者 / 投资关系&quot;">​</a></h3><p>提供公司（或基金管理人）的投资者关系信息。</p><hr><blockquote><p>以上行情、资讯及其他数据来自第三方数据源，仅供参考，不构成投资建议。</p></blockquote><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/market-data">行情数据</a></li></ul>',78)])])}const p=a(i,[["render",d]]);export{c as __pageData,p as default};
